INSERT INTO bug_bounty_submissions (operative_name, title, severity, component, description, steps, status, created_at)
VALUES
  ('V0idWalker', 'Auth token persists after forced logout', 'Critical', 'Auth Service', 'When a user is force-logged out by an admin, the JWT token remains valid in localStorage and can be reused to make authenticated API calls.', '1. Login as user\n2. Admin force-logs out user\n3. Use stored token to call /api/profile\n4. Request succeeds with stale token', 'received', '2026-03-06T10:19:34.743Z'),
  ('NeoConstruct', 'Qi calculation overflow on level 99+', 'Critical', 'Qi Engine', 'Qi values wrap around to negative when a player exceeds level 99 due to integer overflow in the XP multiplier.', '1. Reach level 99\n2. Gain enough XP to level up\n3. Qi value becomes negative', 'fixed', '2026-03-16T18:19:34.743Z'),
  ('GhostWire', 'Race condition in Spirit Stone transfer', 'Critical', 'Spirit Stone Economy', 'Two simultaneous transfer requests can both succeed, duplicating Spirit Stones. Balance check is not atomic.', '1. Have 100 Spirit Stones\n2. Send two simultaneous transfers for 100 each\n3. Both succeed', 'fixed', '2026-03-09T04:19:34.743Z'),
  ('ShadowPulse', 'Session hijack via predictable session IDs', 'Critical', 'Session Handler', 'Session IDs follow a predictable sequential pattern allowing enumeration and hijacking.', '1. Create multiple sessions\n2. Note ID pattern\n3. Predict next session ID\n4. Access another user session', 'received', '2026-03-16T23:19:34.743Z'),
  ('CipherNova', 'SQL injection in leaderboard search', 'Critical', 'Leaderboard', 'Player search field does not sanitize input, allowing SQL injection through the name parameter.', '1. Go to Leaderboard\n2. Enter: '' OR 1=1 --\n3. All players returned', 'confirmed', '2026-03-10T00:19:34.743Z'),
  ('ByteWraith', 'XSS in guild name field', 'Critical', 'Guild System', 'Guild names rendered without escaping. Script tags in guild names execute for other players.', '1. Create guild with script tag name\n2. Another user views guild list\n3. JS executes', 'fixed', '2026-03-07T19:19:34.743Z'),
  ('ZeroCool', 'Combat damage multiplier stacks infinitely', 'High', 'Combat System', 'Critical hit damage multiplier does not reset between rounds, stacking exponentially across fights.', '1. Enter combat\n2. Land 3 critical hits\n3. Exit and re-enter\n4. First hit applies previous stack', 'rejected', '2026-03-03T09:19:34.743Z'),
  ('IronSigma', 'Inventory duplication on disconnect', 'High', 'Inventory Manager', 'Client disconnect mid-transaction while equipping causes item to appear in both inventory and equipped slots.', '1. Start equipping item\n2. Kill network mid-animation\n3. Reconnect\n4. Item duplicated', 'rejected', '2026-03-11T22:19:34.743Z'),
  ('NullVector', 'Notification spam on achievement unlock', 'High', 'Notification Hub', 'Achievement notification fires repeatedly on every profile page load instead of once.', '1. Unlock achievement\n2. Navigate to profile\n3. Navigate away and back\n4. Notification fires again', 'confirmed', '2026-03-11T22:19:34.743Z'),
  ('PhantomEdge', 'Leaderboard shows deleted accounts', 'High', 'Leaderboard', 'Deleted accounts still appear on leaderboard. Cleanup job misses leaderboard entries.', '1. Note player on leaderboard\n2. Delete account\n3. Refresh leaderboard\n4. Still visible', 'rejected', '2026-03-09T20:19:34.743Z'),
  ('ArcReaper', 'Profile image upload bypasses size limit', 'High', 'Profile Service', '2MB limit only enforced client-side. Direct API calls upload arbitrarily large files.', '1. POST 50MB image to /api/profile/avatar\n2. Upload succeeds\n3. No server validation', 'fixed', '2026-03-06T18:19:34.743Z'),
  ('HexMantis', 'Daily login streak resets on timezone change', 'High', 'Daily Login', 'Changing device timezone breaks daily login streak calculation, resetting to 0.', '1. Have 7-day streak\n2. Change timezone\n3. Open app\n4. Streak shows 0', 'rejected', '2026-03-17T02:19:34.743Z'),
  ('DeadPixel', 'Quest completion callback fires twice', 'High', 'Quest Engine', 'Quest completion handler fires twice on final objective, awarding double rewards.', '1. Accept quest\n2. Complete all objectives\n3. Rewards doubled', 'received', '2026-03-15T22:19:34.743Z'),
  ('QuantumDrift', 'Matchmaking pairs players with 50+ level gap', 'High', 'Matchmaking', 'Algorithm pairs level 5 with level 60+ during off-peak hours.', '1. Queue as level 5 off-peak\n2. Matched with level 60+', 'rejected', '2026-03-04T22:19:34.743Z'),
  ('SilkThread', 'Achievement tracker shows 101% completion', 'Medium', 'Achievement Tracker', 'Completion percentage exceeds 100% due to rounding error with hidden achievements.', '1. Complete all visible achievements\n2. Unlock hidden one\n3. Shows 101%', 'received', '2026-03-07T21:19:34.743Z'),
  ('RedShift', 'Guild chat messages appear out of order', 'Medium', 'Guild System', 'Messages appear out of chronological order when sent within the same second.', '1. Three members send messages rapidly\n2. Messages not in send-order', 'fixed', '2026-03-06T21:19:34.743Z'),
  ('BinaryGhost', 'Qi bar animation stutters on low-end devices', 'Medium', 'Qi Engine', 'Qi progress bar animation causes frame drops on devices under 4GB RAM.', '1. Open app on low-end device\n2. Trigger Qi bar animation\n3. Frame drops observed', 'rejected', '2026-03-10T14:19:34.743Z'),
  ('NightCrawler', 'Combat log truncates after 50 entries', 'Medium', 'Combat System', 'Combat log only keeps last 50 entries. Longer fights lose early-round data.', '1. Fight 50+ rounds\n2. Try scrolling to early rounds\n3. Data gone', 'rejected', '2026-03-05T09:19:34.743Z'),
  ('DataSpike', 'Notification badge count desyncs', 'Medium', 'Notification Hub', 'Unread badge shows different count than actual unread notifications.', '1. Receive 5 notifications\n2. Read 2\n3. Badge still shows 5', 'received', '2026-03-10T14:19:34.743Z'),
  ('EchoVoid', 'Profile bio allows HTML entities', 'Medium', 'Profile Service', 'HTML entities render as raw text instead of decoded characters in bio.', '1. Set bio to "Tom &amp; Jerry"\n2. Shows literal &amp;', 'confirmed', '2026-03-09T02:19:34.743Z'),
  ('V0idWalker', 'Inventory sort resets on page change', 'Medium', 'Inventory Manager', 'Rarity sort resets to default when navigating to page 2.', '1. Sort by rarity\n2. Go to page 2\n3. Back to default sort', 'received', '2026-03-14T00:19:34.743Z'),
  ('NeoConstruct', 'Spirit Stone history missing timestamps', 'Medium', 'Spirit Stone Economy', 'Transaction history shows "Invalid Date" for Spirit Stone transfers.', '1. Transfer Spirit Stones\n2. Check history\n3. "Invalid Date" shown', 'rejected', '2026-03-07T20:19:34.743Z'),
  ('GhostWire', 'Session timeout too aggressive on mobile', 'Medium', 'Session Handler', 'Mobile sessions timeout after 5min backgrounding, forcing re-login.', '1. Login on mobile\n2. Switch apps 5 min\n3. Return — forced re-login', 'received', '2026-03-15T00:19:34.743Z'),
  ('ShadowPulse', 'Auth error leaks email existence', 'Medium', 'Auth Service', 'Login errors differ between wrong password and account not found, enabling email enumeration.', '1. Try non-existent email — "Not found"\n2. Try valid email wrong pass — "Incorrect password"', 'rejected', '2026-03-09T07:19:34.743Z'),
  ('CipherNova', 'Leaderboard pagination off by one', 'Low', 'Leaderboard', 'Last player on page 1 duplicates as first on page 2.', '1. View page 1 last entry\n2. Go to page 2\n3. Same player first', 'fixed', '2026-03-06T00:19:34.743Z'),
  ('ByteWraith', 'Quest description overflows on small screens', 'Low', 'Quest Engine', 'Long quest descriptions overflow container on screens under 360px.', '1. Open long quest on narrow screen\n2. Text overlaps buttons', 'fixed', '2026-03-16T05:19:34.743Z'),
  ('ZeroCool', 'Guild invite button has no loading state', 'Low', 'Guild System', 'No loading indicator on invite button, users click multiple times sending duplicates.', '1. Click Invite\n2. No feedback\n3. Click again\n4. Duplicate invite sent', 'confirmed', '2026-03-16T04:19:34.743Z'),
  ('IronSigma', 'Achievement sound plays in silent mode', 'Low', 'Achievement Tracker', 'Achievement sounds play even when app sound is toggled off.', '1. Turn off sound\n2. Unlock achievement\n3. Sound plays', 'received', '2026-03-09T07:19:34.743Z'),
  ('NullVector', 'Combat skip button misaligned on tablet', 'Low', 'Combat System', 'Skip Animation button overlaps damage numbers on tablet landscape.', '1. Enter combat on tablet landscape\n2. Attack\n3. Button and damage overlap', 'received', '2026-03-09T15:19:34.743Z'),
