  ('ArcReaper', 'Notification sound plays twice on iOS', 'Low', 'Notification Hub', 'Push notifications trigger both system and in-app sounds simultaneously on iOS.', '1. Receive notification on iOS\n2. Two sounds play', 'received', '2026-03-14T18:19:34.743Z'),
  ('HexMantis', 'Inventory tooltip flickers on hover', 'Low', 'Inventory Manager', 'Tooltip rapidly appears/disappears when cursor is near item icon edge.', '1. Hover on edge of inventory item\n2. Tooltip flickers', 'confirmed', '2026-03-10T06:19:34.743Z'),
  ('DeadPixel', 'Spirit Stone icon invisible in dark mode', 'Low', 'Spirit Stone Economy', 'Spirit Stone icon uses black fill, invisible on dark backgrounds.', '1. Enable dark mode\n2. Look at balance\n3. Icon invisible', 'received', '2026-03-07T23:19:34.743Z'),
  ('QuantumDrift', 'Daily reward modal blocks interaction', 'Low', 'Daily Login', 'Daily reward modal has no close button and no outside-click dismiss.', '1. Login\n2. Modal appears\n3. No way to close without refresh', 'received', '2026-03-13T09:19:34.743Z'),
  ('SilkThread', 'Matchmaking cancel unresponsive for 2s', 'Low', 'Matchmaking', 'Cancel button does not respond for ~2 seconds after clicking Find Match.', '1. Click Find Match\n2. Try cancel immediately\n3. No response for 2s', 'confirmed', '2026-03-09T21:19:34.743Z'),
  ('RedShift', 'Session count double-counts refreshes', 'Low', 'Session Handler', 'Each page refresh counted as new session, inflating analytics.', '1. Login once\n2. Refresh 5 times\n3. Analytics shows 6 sessions', 'received', '2026-03-08T14:19:34.743Z'),
  ('BinaryGhost', 'Password reset link expires too fast', 'Medium', 'Auth Service', 'Reset links expire in 10 min but emails take 8-9 min to arrive.', '1. Request reset\n2. Email arrives in ~9 min\n3. Link already expired', 'rejected', '2026-03-15T22:19:34.743Z'),
  ('NightCrawler', 'Combat rewards not showing in summary', 'Medium', 'Combat System', 'Post-combat summary shows 0 rewards for fights over 10 minutes.', '1. Fight over 10 min\n2. Summary shows 0\n3. Rewards are actually awarded', 'received', '2026-03-08T06:19:34.743Z'),
  ('DataSpike', 'Qi Engine memory leak on level-ups', 'High', 'Qi Engine', 'Event listeners accumulate on each level-up without cleanup, memory grows ~5MB per level.', '1. Long play session\n2. Level up multiple times\n3. Memory grows indefinitely', 'fixed', '2026-03-05T07:19:34.743Z'),
  ('EchoVoid', 'Leaderboard API exposes full user objects', 'High', 'Leaderboard', '/api/leaderboard returns complete user objects including email and hashed password.', '1. GET /api/leaderboard\n2. Response contains emails, hashed passwords', 'received', '2026-03-15T16:19:34.743Z'),
  ('V0idWalker', 'Guild creation allows duplicate names', 'Medium', 'Guild System', 'Multiple guilds can have the exact same name, causing confusion.', '1. Create guild "Phoenix"\n2. Another creates "Phoenix"\n3. Both exist', 'received', '2026-03-03T10:19:34.743Z'),
  ('NeoConstruct', 'Achievement progress resets on app update', 'High', 'Achievement Tracker', 'Progress counters reset to 0 on update because state is in local storage not server.', '1. Have partial progress (73/100)\n2. Update app\n3. Counter resets to 0', 'confirmed', '2026-03-12T17:19:34.743Z'),
  ('GhostWire', 'Quest timer uses wrong time source', 'Medium', 'Quest Engine', 'Timer uses client time but deadline uses server time, causing desync when app is closed.', '1. Accept 30 min quest\n2. Close app 20 min\n3. Timer shows 10 min but server has full time', 'confirmed', '2026-03-11T12:19:34.743Z'),
